const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const f = body.filters || {};
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 100, 1), 500);
const sinceIso = f.since || null;

function qsBase(orderCol) {
  const parts = ['order=' + orderCol + '.desc', 'limit=' + limit];
  if (sinceIso) parts.push(orderCol + '=gte.' + encodeURIComponent(sinceIso));
  return parts;
}

const qsAuctions = ['select=id,avatar_id,streaming_session_id,item_title,item_description,item_category,item_photos,reserve_price_cents,status,scheduled_open_at,actual_open_at,scheduled_close_at,actual_close_at,extensions_used,current_high_bid_cents,current_high_bid_id,min_increment_cents,winning_bid_id,seller_id,created_at,updated_at']
  .concat(qsBase('scheduled_open_at'));
if (f.status && f.status !== 'all') qsAuctions.push('status=eq.' + encodeURIComponent(f.status));

// Bids — flat list within the window; aggregated client-side per auction
const qsBids = [
  'select=id,auction_id,bidder_id,amount_cents,placed_at,status',
  'order=placed_at.desc',
  'limit=' + (limit * 10)
].join('&');

return { json: {
  token: token,
  qs_auctions: qsAuctions.join('&'),
  qs_bids:     qsBids,
  qs_avatar:   'select=id,avatar_name,personality,vertical_id,active&avatar_name=eq.LUXI&limit=1',
  filters: f,
  limit: limit
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: { ok: true, qs_auctions: x.qs_auctions, qs_bids: x.qs_bids, qs_avatar: x.qs_avatar, filters: x.filters } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const auctions = allOf('Query Auctions');
const bids     = allOf('Query Bids');
const avatars  = allOf('Query LUXI Avatar');
const luxi     = avatars[0] || null;

// Aggregate bids per auction.
const bidCount = {};
const bidderSet = {};
bids.forEach(function (b) {
  if (!b.auction_id) return;
  bidCount[b.auction_id] = (bidCount[b.auction_id] || 0) + 1;
  if (!bidderSet[b.auction_id]) bidderSet[b.auction_id] = {};
  if (b.bidder_id) bidderSet[b.auction_id][b.bidder_id] = true;
});

// Enrich auctions with bid counts.
const enriched = auctions.map(function (a) {
  return Object.assign({}, a, {
    bid_count:    bidCount[a.id] || 0,
    bidder_count: bidderSet[a.id] ? Object.keys(bidderSet[a.id]).length : 0
  });
});

// Group by status for the dashboard columns.
const byStatus = { scheduled: [], open: [], extended: [], closed_sold: [], closed_unsold: [], cancelled: [] };
enriched.forEach(function (a) {
  const s = a.status || 'scheduled';
  if (!byStatus[s]) byStatus[s] = [];
  byStatus[s].push(a);
});

const now = Date.now();
const totalGmvCents = enriched
  .filter(function (a) { return a.status === 'closed_sold'; })
  .reduce(function (s, a) { return s + (a.current_high_bid_cents || 0); }, 0);

return { json: {
  ok: true,
  avatar: luxi,
  auctions: enriched,
  by_status: byStatus,
  counts: {
    total:          enriched.length,
    scheduled:      byStatus.scheduled.length,
    live:           byStatus.open.length + byStatus.extended.length,
    closed_sold:    byStatus.closed_sold.length,
    closed_unsold:  byStatus.closed_unsold.length,
    cancelled:      byStatus.cancelled.length
  },
  gmv_cents: totalGmvCents,
  bids_examined: bids.length,
  generated_at: new Date(now).toISOString()
} };
